INSERT INTO `faqs` (`id`, `question`, `answer`, `written_by`, `created_at`, `updated_at`) VALUES
(1, 'What are your clinic hours?', 'Our clinic is open Monday to Saturday from 9:00 AM to 6:00 PM. We are closed on Sundays.', 'me', '2025-05-20 00:44:34', '2025-05-20 00:44:34'),
(2, 'Do I need an appointment before visiting?', 'Yes, we recommend scheduling an appointment to ensure availability and reduce waiting time.', 'me', '2025-05-20 00:44:45', '2025-05-20 00:44:45'),
(3, 'Where is your clinic located?', 'We are located at P-2 , 241-44 ,Tower-OAK Paramount golfforest Zeta-1 Gr.Noida 201308. Please check our contact page for directions and a map.', 'me', '2025-05-20 00:44:58', '2025-06-18 01:42:31'),
(4, 'Why should I choose your clinic for physical therapy?', 'We offer personalized care, experienced licensed therapists, and proven treatment methods in a comfortable and welcoming environment.', 'me', '2025-05-20 00:45:10', '2025-05-20 00:45:10'),
(5, 'What should I bring to my first appointment?', 'Please bring your ID, insurance card, any relevant medical records, and wear comfortable clothing for movement.', 'me', '2025-05-20 00:45:26', '2025-05-20 00:45:26'),
(6, 'How long is a typical physical therapy session?', 'Most sessions last between 30 to 60 minutes depending on your treatment plan.', 'me', '2025-05-20 00:45:43', '2025-05-20 00:45:43'),
(7, 'Can children or seniors receive therapy at your clinic?', 'Yes, we provide therapy for all age groups, including pediatric and geriatric care.', 'me', '2025-05-20 00:45:55', '2025-05-20 00:45:55'),
(8, 'Will I see the same therapist every time?', 'We aim to maintain consistency by assigning the same therapist to follow your treatment journey whenever possible.', 'me', '2025-05-20 00:46:09', '2025-05-20 00:46:09'),
(9, 'How do I book an appointment?', 'You can book an appointment by calling us, filling out our online form, or visiting the clinic directly during office hours.', 'admin', '2025-05-20 00:46:25', '2025-05-20 00:46:25');

