INSERT INTO `reviews` (`id`, `username`, `posted_date`, `review`, `stars`, `user_image`, `created_at`, `updated_at`) VALUES
(7, 'shadab alam', '2025-06-29', 'Neurigo360 is an excellent physiotherapy and rehabilitation clinic, providing top-class care with a personalized approach. The therapists are highly skilled, attentive, and genuinely dedicated to patient recovery. The clinic is well-equipped with modern facilities, and the treatment plans are customized to each individual’s needs, ensuring faster and more effective results. The environment is professional yet friendly, making patients feel comfortable and motivated throughout their recovery journey. Highly recommended for anyone looking for reliable physiotherapy and rehabilitation service', 5, '1764403517.png', '2025-11-29 08:05:17', '2025-11-29 08:05:17'),
(8, 'Ajay Thakur', '2025-07-29', 'I had an outstanding experience at NURIGO360 for neuro rehabilitation. From the very first appointment, the staff was compassionate, knowledgeable, and truly dedicated to patient recovery. The therapists tailored a treatment plan specific to my needs, which made a significant difference in my progress.\r\n\r\nThe facility is clean, well-equipped, and offers a calm, supportive environment. I especially appreciated the time the team took to explain each step of the process and adjust exercises as I improved. Their encouragement kept me motivated throughout my recovery.\r\n\r\nThanks to their expertise and support, I’ve regained much of my strength and confidence. I highly recommend NEURIGO360 to anyone seeking high-quality neuro rehab services.', 5, '1764403553.png', '2025-11-29 08:05:53', '2025-11-29 08:05:53'),
(9, 'Ricki Singh', '2025-07-29', 'I had a great experience at Dr. Partap’s Spine Rehabilitation Centre(Neuro360). Thanks to his expert guidance and treatment, I was able to start walking with walker. Dr. Partap’s knowledge, dedication, and personal care made all the difference in my recovery. The centre has excellent facilities and a supportive team that makes every session comfortable and effective.\r\n\r\nI’m truly grateful for the results and highly recommend Dr. Partap to anyone in need of spine rehabilitation.', 5, '1764403593.png', '2025-11-29 08:06:33', '2025-11-29 08:06:33'),
(10, 'monika Gaur', '2025-07-29', 'Neurigo 360 is an excellent rehab centre led by Dr. Pratap . Patients who couldn’t even walk have shown remarkable recovery through regular therapy. The treatment is highly effective, and the entire team is truly dedicated to patient care.', 5, '1764403620.png', '2025-11-29 08:07:00', '2025-11-29 08:07:15'),
(12, 'akshay kumar', '2025-06-29', 'I am akshay spinal cord injury(L3) patient from karnatka .I have been taking here therapy since 1 month . I have seen major recovery as I was in AFO and now I am able to take weight on my legs without AFO. Fastest recovery centre.', 5, '1764403679.png', '2025-11-29 08:07:59', '2025-11-29 08:07:59'),
(14, 'Pawan Sharma', '2025-07-29', 'Excellent services and most reliable physiotherapist. They provide world class physiotherapy and yes they walk step by step with their patients to make impossible to possible.', 5, '1764403720.png', '2025-11-29 08:08:40', '2025-11-29 08:08:40'),
(16, 'SWA-JAY AGRO', '2025-11-26', 'i perfect lagega: Best Review for Nerogo360 \"Nerogo360 ne literally meri expectations se zyada perform kiya. Build quality strong hai, features practical hain aur performance super smooth. Sabse achi baat - iska interface simple aur user-friendly hai, beginners bhi easy use kar sakte hain. Battery backup bhi kaafi impressive hai. Price ke hisaab se yeh definitely value-for-money product hai. Main 100% recommend karta/karte hoon agar aap ek reliable aur long-lasting device dhoond rahe ho.\".🙏👀🥰', 5, '1764403760.png', '2025-11-29 08:09:20', '2025-11-29 08:09:20'),
(17, 'Dr AniL YadaV', '2025-07-29', 'Best neuro rehab and team', 5, '1764403816.png', '2025-11-29 08:10:16', '2025-11-29 08:10:16'),
(19, 'Baba Singh', '2025-11-26', 'Good behaviour and best recovery exercise.... thanks 👍 Neurigo360..and thanks Dr\'s', 5, '1764403857.png', '2025-11-29 08:10:57', '2025-11-29 08:10:57'),
(20, 'TaNuJ SiNgH', '2025-11-25', 'Best and fast recovery', 5, '1764403890.png', '2025-11-29 08:11:30', '2025-11-29 08:11:30');

