pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><br></span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">1. Initial Assessment</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Before we begin, we assess your blood pressure, heart rate, degree of fitness, and any health concerns. This helps us build a safe and effective plan for you.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><br></span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">2. Personalized Exercise Plan</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">We may begin with quick walks or low-impact exercises and progressively increase time and intensity based on your age, condition, and objective.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><br></span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">3. Supervised Training</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">We provide monitored exercise sessions where vital signs are monitored during workouts to guarantee safety for individuals with heart or lung issues.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><br></span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">4. Breathing Techniques and Warmups</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">To prevent exhaustion or damage, we teach appropriate warm-up, breathing, and cool-down techniques.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><br></span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">5. Progress Tracking and Motivation</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">We track your progress regularly and adjust your plan to keep it effective and interesting.</span></p><h3 dir=\"ltr\" style=\"line-height:1.38;margin-top:16pt;margin-bottom:4pt;\"><span style=\"font-size:13.999999999999998pt;font-family:Arial,sans-serif;color:#434343;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Why Choose Us?</span></h3><ul style=\"margin-top:0;margin-bottom:0;padding-inline-start:48px;\"><li dir=\"ltr\" style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;\" aria-level=\"1\"><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\" role=\"presentation\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Experienced physiotherapists and rehab specialists</span></p></li><li dir=\"ltr\" style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;\" aria-level=\"1\"><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\" role=\"presentation\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Heart-safe equipment and trained supervision</span></p></li><li dir=\"ltr\" style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;\" aria-level=\"1\"><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\" role=\"presentation\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Programs specifically designed for the elderly, heart patients, and overall fitness</span></p></li><li dir=\"ltr\" style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;\" aria-level=\"1\"><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\" role=\"presentation\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Focus on gradual, long-term improvement—not quick fixes.</span></p></li><li dir=\"ltr\" style=\"list-style-type:disc;font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;\" aria-level=\"1\"><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\" role=\"presentation\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Encouraging, non-judgmental environment</span></p></li></ul><p data-start=\"94\" data-end=\"368\"><br></p>', 1, '2025-06-24 00:43:12', '2025-11-05 07:22:52'),
(20, 'Gait training', '1759835002.jpeg', 'service', '<p data-start=\"100\" data-end=\"455\">Gait training is a type of physical therapy that helps people <strong data-start=\"162\" data-end=\"194\">learn or relearn how to walk</strong> safely and effectively. It focuses on improving the way you move your legs, balance your body, and take steps. If you’ve had an injury, surgery, stroke, or neurological condition, gait training can help you walk more confidently and reduce the risk of falling.</p><p data-start=\"457\" data-end=\"608\">At our center, we provide <strong data-start=\"483\" data-end=\"522\">personalized gait training programs</strong> designed to help people of all ages walk better, feel stronger, and move more freely.</p><hr data-start=\"610\" data-end=\"613\"><h3 data-start=\"615\" data-end=\"636\"><strong data-start=\"619\" data-end=\"636\">What is Gait?</strong></h3><p data-start=\"638\" data-end=\"892\">\"Gait\" simply means <strong data-start=\"658\" data-end=\"674\">how you walk</strong>—your posture, step pattern, foot placement, and balance. A normal gait lets you move smoothly and safely. But injury, weakness, or a medical condition can affect your gait, making walking difficult, uneven, or unsafe.</p><hr data-start=\"894\" data-end=\"897\"><h3 data-start=\"899\" data-end=\"931\"><strong data-start=\"903\" data-end=\"931\">Who Needs Gait Training?</strong></h3><p data-start=\"933\" data-end=\"978\">Gait training is helpful for people who have:</p><ul data-start=\"979\" data-end=\"1410\">\r\n<li data-start=\"979\" data-end=\"1019\">\r\n<p data-start=\"981\" data-end=\"1019\">Had a <strong data-start=\"987\" data-end=\"997\">stroke</strong> or <strong data-start=\"1001\" data-end=\"1017\">brain injury</strong></p>\r\n</li>\r\n<li data-start=\"1020\" data-end=\"1055\">\r\n<p data-start=\"1022\" data-end=\"1055\">Been in an <strong data-start=\"1033\" data-end=\"1053\">accident or fall</strong></p>\r\n</li>\r\n<li data-start=\"1056\" data-end=\"1132\">\r\n<p data-start=\"1058\" data-end=\"1132\">Suffered from <strong data-start=\"1072\" data-end=\"1102\">fractures or joint surgery</strong> (like hip/knee replacement)</p>\r\n</li>\r\n<li data-start=\"1133\" data-end=\"1240\">\r\n<p data-start=\"1135\" data-end=\"1240\"><strong data-start=\"1135\" data-end=\"1162\">Neurological conditions</strong> like <strong data-start=\"1168\" data-end=\"1191\">Parkinson’s disease</strong>, <strong data-start=\"1193\" data-end=\"1211\">cerebral palsy</strong>, or <strong data-start=\"1216\" data-end=\"1238\">multiple sclerosis</strong></p>\r\n</li>\r\n<li data-start=\"1241\" data-end=\"1313\">\r\n<p data-start=\"1243\" data-end=\"1313\">Muscle weakness due to <strong data-start=\"1266\" data-end=\"1295\">aging, long hospital stay</strong>, or <strong data-start=\"1300\" data-end=\"1311\">illness</strong></p>\r\n</li>\r\n<li data-start=\"1314\" data-end=\"1359\">\r\n<p data-start=\"1316\" data-end=\"1359\"><strong data-start=\"1316\" data-end=\"1330\">Amputation</strong> or prosthetic limb fitting</p>\r\n</li>\r\n<li data-start=\"1360\" data-end=\"1410\">\r\n<p data-start=\"1362\" data-end=\"1410\">Trouble with balance, coordination, or posture</p>\r\n</li>\r\n</ul><p data-start=\"1412\" data-end=\"1489\">Even children with developmental delays may benefit from early gait training.</p><hr data-start=\"1491\" data-end=\"1494\"><h3 data-start=\"1496\" data-end=\"1526\"><strong data-start=\"1500\" data-end=\"1526\">Goals of Gait Training</strong></h3><p data-start=\"1528\" data-end=\"1568\">The main purpose of gait training is to:</p><ul data-start=\"1569\" data-end=\"1891\">\r\n<li data-start=\"1569\" data-end=\"1609\">\r\n<p data-start=\"1571\" data-end=\"1609\">Improve <strong data-start=\"1579\" data-end=\"1607\">balance and coordination</strong></p>\r\n</li>\r\n<li data-start=\"1610\" data-end=\"1677\">\r\n<p data-start=\"1612\" data-end=\"1677\">Correct walking patterns (step length, posture, foot placement)</p>\r\n</li>\r\n<li data-start=\"1678\" data-end=\"1727\">\r\n<p data-start=\"1680\" data-end=\"1727\">Strengthen <strong data-start=\"1691\" data-end=\"1725\">leg muscles and core stability</strong></p>\r\n</li>\r\n<li data-start=\"1728\" data-end=\"1772\">\r\n<p data-start=\"1730\" data-end=\"1772\">Increase <strong data-start=\"1739\" data-end=\"1770\">walking speed and endurance</strong></p>\r\n</li>\r\n<li data-start=\"1773\" data-end=\"1824\">\r\n<p data-start=\"1775\" data-end=\"1824\">Build confidence and reduce <strong data-start=\"1803\" data-end=\"1822\">risk of falling</strong></p>\r\n</li>\r\n<li data-start=\"1825\" data-end=\"1891\">\r\n<p data-start=\"1827\" data-end=\"1891\">Help with <strong data-start=\"1837\" data-end=\"1864\">using assistive devices</strong> (walkers, crutches, canes)</p>\r\n</li>\r\n</ul><hr data-start=\"1893\" data-end=\"1896\"><h3 data-start=\"1898\" data-end=\"1938\"><strong data-start=\"1902\" data-end=\"1938\">What Does Gait Training Include?</strong></h3><h4 data-start=\"1940\" data-end=\"1962\">1. <strong data-start=\"1948\" data-end=\"1962\">Assessment</strong></h4><p data-start=\"1963\" data-end=\"2119\">We begin with a full analysis of how you walk—looking at step patterns, balance, muscle strength, and flexibility. This helps us identify the problem areas.</p><h4 data-start=\"2121\" data-end=\"2154\">2. <strong data-start=\"2129\" data-end=\"2154\">Therapeutic Exercises</strong></h4><p data-start=\"2155\" data-end=\"2219\">We use a series of exercises and techniques to improve movement:</p><ul data-start=\"2220\" data-end=\"2429\">\r\n<li data-start=\"2220\" data-end=\"2249\">\r\n<p data-start=\"2222\" data-end=\"2249\">Leg and hip strengthening</p>\r\n</li>\r\n<li data-start=\"2250\" data-end=\"2288\">\r\n<p data-start=\"2252\" data-end=\"2288\">Weight shifting and balance drills</p>\r\n</li>\r\n<li data-start=\"2289\" data-end=\"2336\">\r\n<p data-start=\"2291\" data-end=\"2336\">Step training (sideways, forward, backward)</p>\r\n</li>\r\n<li data-start=\"2337\" data-end=\"2379\">\r\n<p data-start=\"2339\" data-end=\"2379\">Stair climbing and obstacle navigation</p>\r\n</li>\r\n<li data-start=\"2380\" data-end=\"2429\">\r\n<p data-start=\"2382\" data-end=\"2429\">Mirror and video feedback for visual learning</p>\r\n</li>\r\n</ul><h4 data-start=\"2431\" data-end=\"2468\">3. <strong data-start=\"2439\" data-end=\"2468\">Assistive Device Training</strong></h4><p data-start=\"2469\" data-end=\"2557\">We teach you how to safely use walkers, canes, crutches, or orthotic supports if needed.</p><h4 data-start=\"2559\" data-end=\"2609\">4. <strong data-start=\"2567\" data-end=\"2609\">Treadmill and Balance Platform Therapy</strong></h4><p data-start=\"2610\" data-end=\"2714\">In some cases, we use body-weight support treadmills or balance boards for advanced gait rehabilitation.</p><h4 data-start=\"2716\" data-end=\"2761\">5. <strong data-start=\"2724\" data-end=\"2761\">Home Exercise and Family Guidance</strong></h4><p data-start=\"2762\" data-end=\"2848\">We teach simple home exercises and educate caregivers on how to support your progress.</p><hr data-start=\"2850\" data-end=\"2853\"><h3 data-start=\"2855\" data-end=\"2877\"><strong data-start=\"2859\" data-end=\"2877\">Why Choose Us?</strong></h3><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><ul data-start=\"2879\" data-end=\"3158\">\r\n<li data-start=\"2879\" data-end=\"2934\">\r\n<p data-start=\"2881\" data-end=\"2934\">Expert <strong data-start=\"2888\" data-end=\"2932\">physiotherapists and rehab professionals</strong></p>\r\n</li>\r\n<li data-start=\"2935\" data-end=\"2986\">\r\n<p data-start=\"2937\" data-end=\"2986\"><strong data-start=\"2937\" data-end=\"2957\">Modern equipment</strong> and supportive environment</p>\r\n</li>\r\n<li data-start=\"2987\" data-end=\"3048\">\r\n<p data-start=\"2989\" data-end=\"3048\"><strong data-start=\"2989\" data-end=\"3019\">Customized treatment plans</strong> for each age and condition</p>\r\n</li>\r\n<li data-start=\"3049\" data-end=\"3108\">\r\n<p data-start=\"3051\" data-end=\"3108\">Focus on <strong data-start=\"3060\" data-end=\"3106\">safety, confidence, and long-term recovery</strong></p>\r\n</li>\r\n<li data-start=\"3109\" data-end=\"3158\">\r\n<p data-start=\"3111\" data-end=\"3158\">Friendly care that motivates you to keep moving</p>\r\n</li>\r\n</ul>', 1, '2025-06-24 00:46:49', '2025-10-07 11:03:22');
INSERT INTO `services` (`id`, `service`, `image`, `category`, `description`, `active`, `created_at`, `updated_at`) VALUES
(21, 'Occupational therapy', '1750746059.jpg', 'service', '<p data-start=\"103\" data-end=\"480\">Occupational therapy is a type of healthcare that helps people of all ages improve the skills they need for <strong data-start=\"211\" data-end=\"228\">everyday life</strong>. Whether it’s a child learning to write, an adult recovering from an injury, or a senior struggling with dressing or cooking, <strong data-start=\"355\" data-end=\"388\">occupational therapists (OTs)</strong> help individuals become more independent, confident, and capable in their daily activities.</p><p data-start=\"482\" data-end=\"641\">At our center, we offer personalized occupational therapy to support your physical, mental, and emotional well-being—so you can do the things that matter most.</p><hr data-start=\"643\" data-end=\"646\"><h3 data-start=\"648\" data-end=\"685\"><strong data-start=\"652\" data-end=\"685\">What is Occupational Therapy?</strong></h3><p data-start=\"687\" data-end=\"791\">Occupational therapy focuses on helping you perform <strong data-start=\"739\" data-end=\"756\">“occupations”</strong>—the things you do every day, like:</p><ul data-start=\"792\" data-end=\"959\">\r\n<li data-start=\"792\" data-end=\"811\">\r\n<p data-start=\"794\" data-end=\"811\">Getting dressed</p>\r\n</li>\r\n<li data-start=\"812\" data-end=\"835\">\r\n<p data-start=\"814\" data-end=\"835\">Eating and grooming</p>\r\n</li>\r\n<li data-start=\"836\" data-end=\"867\">\r\n<p data-start=\"838\" data-end=\"867\">Writing or using a computer</p>\r\n</li>\r\n<li data-start=\"868\" data-end=\"904\">\r\n<p data-start=\"870\" data-end=\"904\">Cooking or using household tools</p>\r\n</li>\r\n<li data-start=\"905\" data-end=\"931\">\r\n<p data-start=\"907\" data-end=\"931\">Playing (for children)</p>\r\n</li>\r\n<li data-start=\"932\" data-end=\"959\">\r\n<p data-start=\"934\" data-end=\"959\">Going to school or work</p>\r\n</li>\r\n</ul><p data-start=\"961\" data-end=\"1135\">It’s not about finding a job (even though the word \"occupational\" sounds like that)—it’s about helping you be <strong data-start=\"1071\" data-end=\"1101\">as independent as possible</strong> in your daily roles and routines.</p><hr data-start=\"1137\" data-end=\"1140\"><h3 data-start=\"1142\" data-end=\"1181\"><strong data-start=\"1146\" data-end=\"1181\">Who Needs Occupational Therapy?</strong></h3><p data-start=\"1183\" data-end=\"1219\">Occupational therapy is helpful for:</p><ul data-start=\"1220\" data-end=\"1684\">\r\n<li data-start=\"1220\" data-end=\"1295\">\r\n<p data-start=\"1222\" data-end=\"1295\"><strong data-start=\"1222\" data-end=\"1234\">Children</strong> with developmental delays, autism, ADHD, or sensory issues</p>\r\n</li>\r\n<li data-start=\"1296\" data-end=\"1354\">\r\n<p data-start=\"1298\" data-end=\"1354\"><strong data-start=\"1298\" data-end=\"1318\">Stroke survivors</strong> or people with <strong data-start=\"1334\" data-end=\"1352\">brain injuries</strong></p>\r\n</li>\r\n<li data-start=\"1355\" data-end=\"1425\">\r\n<p data-start=\"1357\" data-end=\"1425\">Individuals recovering from <strong data-start=\"1385\" data-end=\"1423\">accidents, fractures, or surgeries</strong></p>\r\n</li>\r\n<li data-start=\"1426\" data-end=\"1507\">\r\n<p data-start=\"1428\" data-end=\"1507\">People with <strong data-start=\"1440\" data-end=\"1453\">arthritis</strong>, <strong data-start=\"1455\" data-end=\"1478\">Parkinson’s disease</strong>, or <strong data-start=\"1483\" data-end=\"1505\">multiple sclerosis</strong></p>\r\n</li>\r\n<li data-start=\"1508\" data-end=\"1599\">\r\n<p data-start=\"1510\" data-end=\"1599\">Seniors with <strong data-start=\"1523\" data-end=\"1553\">aging-related difficulties</strong> (like memory loss or reduced hand strength)</p>\r\n</li>\r\n<li data-start=\"1600\" data-end=\"1684\">\r\n<p data-start=\"1602\" data-end=\"1684\">Anyone having trouble with daily tasks due to <strong data-start=\"1648\" data-end=\"1684\">physical or cognitive challenges</strong></p>\r\n</li>\r\n</ul><hr data-start=\"1686\" data-end=\"1689\"><h3 data-start=\"1691\" data-end=\"1728\"><strong data-start=\"1695\" data-end=\"1728\">Goals of Occupational Therapy</strong></h3><ul data-start=\"1730\" data-end=\"2075\">\r\n<li data-start=\"1730\" data-end=\"1779\">\r\n<p data-start=\"1732\" data-end=\"1779\">Increase <strong data-start=\"1741\" data-end=\"1757\">independence</strong> in daily activities</p>\r\n</li>\r\n<li data-start=\"1780\" data-end=\"1860\">\r\n<p data-start=\"1782\" data-end=\"1860\">Improve <strong data-start=\"1790\" data-end=\"1806\">motor skills</strong> (fine motor for hand use, gross motor for movement)</p>\r\n</li>\r\n<li data-start=\"1861\" data-end=\"1917\">\r\n<p data-start=\"1863\" data-end=\"1917\">Develop <strong data-start=\"1871\" data-end=\"1893\">sensory processing</strong> and emotional control</p>\r\n</li>\r\n<li data-start=\"1918\" data-end=\"1961\">\r\n<p data-start=\"1920\" data-end=\"1961\">Enhance <strong data-start=\"1928\" data-end=\"1959\">memory, focus, and planning</strong></p>\r\n</li>\r\n<li data-start=\"1962\" data-end=\"2017\">\r\n<p data-start=\"1964\" data-end=\"2017\">Recommend <strong data-start=\"1974\" data-end=\"1995\">assistive devices</strong> to make life easier</p>\r\n</li>\r\n<li data-start=\"2018\" data-end=\"2075\">\r\n<p data-start=\"2020\" data-end=\"2075\">Create <strong data-start=\"2027\" data-end=\"2048\">safe environments</strong> at home, school, or work</p>\r\n</li>\r\n</ul><hr data-start=\"2077\" data-end=\"2080\"><h3 data-start=\"2082\" data-end=\"2129\"><strong data-start=\"2086\" data-end=\"2129\">What Does Occupational Therapy Involve?</strong></h3><h4 data-start=\"2131\" data-end=\"2153\">1. <strong data-start=\"2139\" data-end=\"2153\">Evaluation</strong></h4><p data-start=\"2154\" data-end=\"2251\">We begin with a full assessment of your strengths, challenges, daily routine, and personal goals.</p><h4 data-start=\"2253\" data-end=\"2280\">2. <strong data-start=\"2261\" data-end=\"2280\">Customized Plan</strong></h4><p data-start=\"2281\" data-end=\"2425\">We create a therapy plan that suits your age, condition, and life goals—whether it’s buttoning a shirt, learning to write, or returning to work.</p><h4 data-start=\"2427\" data-end=\"2461\">3. <strong data-start=\"2435\" data-end=\"2461\">Therapeutic Activities</strong></h4><p data-start=\"2462\" data-end=\"2508\">Depending on your needs, sessions may include:</p><ul data-start=\"2509\" data-end=\"2847\">\r\n<li data-start=\"2509\" data-end=\"2552\">\r\n<p data-start=\"2511\" data-end=\"2552\">Hand and finger strengthening exercises</p>\r\n</li>\r\n<li data-start=\"2553\" data-end=\"2588\">\r\n<p data-start=\"2555\" data-end=\"2588\">Coordination and balance drills</p>\r\n</li>\r\n<li data-start=\"2589\" data-end=\"2659\">\r\n<p data-start=\"2591\" data-end=\"2659\">Practice with self-care tasks (like brushing teeth or tying shoes)</p>\r\n</li>\r\n<li data-start=\"2660\" data-end=\"2707\">\r\n<p data-start=\"2662\" data-end=\"2707\">Cognitive games to improve memory and focus</p>\r\n</li>\r\n<li data-start=\"2708\" data-end=\"2788\">\r\n<p data-start=\"2710\" data-end=\"2788\">Sensory integration activities for children with autism or sensory disorders</p>\r\n</li>\r\n<li data-start=\"2789\" data-end=\"2847\">\r\n<p data-start=\"2791\" data-end=\"2847\">Guidance on using splints, adapted tools, or wheelchairs</p>\r\n</li>\r\n</ul><h4 data-start=\"2849\" data-end=\"2899\">4. <strong data-start=\"2857\" data-end=\"2899\">Home Modifications and Family Training</strong></h4><p data-start=\"2900\" data-end=\"3000\">We suggest changes at home or work to make life easier and train family members to support progress.</p><hr data-start=\"3002\" data-end=\"3005\"><h3 data-start=\"3007\" data-end=\"3029\"><strong data-start=\"3011\" data-end=\"3029\">Why Choose Us?</strong></h3><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><ul data-start=\"3031\" data-end=\"3295\">\r\n<li data-start=\"3031\" data-end=\"3122\">\r\n<p data-start=\"3033\" data-end=\"3122\"><strong data-start=\"3033\" data-end=\"3072\">Experienced occupational therapists</strong> trained in pediatric, adult, and geriatric care</p>\r\n</li>\r\n<li data-start=\"3123\" data-end=\"3187\">\r\n<p data-start=\"3125\" data-end=\"3187\"><strong data-start=\"3125\" data-end=\"3156\">One-on-one therapy sessions</strong> tailored to individual needs</p>\r\n</li>\r\n<li data-start=\"3188\" data-end=\"3236\">\r\n<p data-start=\"3190\" data-end=\"3236\">Friendly, supportive environment for therapy</p>\r\n</li>\r\n<li data-start=\"3237\" data-end=\"3295\">\r\n<p data-start=\"3239\" data-end=\"3295\"><strong data-start=\"3239\" data-end=\"3295\">Focus on functional independence and real-life goals</strong></p></li></ul>', 1, '2025-06-24 00:50:59', '2025-06-24 00:50:59'),
(22, 'Hydrotherapy', '1750746209.jpg', 'service', '<p data-start=\"72\" data-end=\"359\">Hydrotherapy, also known as <strong data-start=\"100\" data-end=\"119\">aquatic therapy</strong>, is a gentle, water-based treatment used to relieve pain, improve movement, and promote relaxation. It uses the natural properties of water—like warmth, buoyancy (floating), and resistance—to support physical healing and mental well-being.</p><p data-start=\"361\" data-end=\"527\">At our center, we offer <strong data-start=\"385\" data-end=\"427\">safe, customized hydrotherapy sessions</strong> guided by trained physiotherapists to help people of all ages recover, strengthen, and feel better.</p><hr data-start=\"529\" data-end=\"532\"><h3 data-start=\"534\" data-end=\"563\"><strong data-start=\"538\" data-end=\"563\">What Is Hydrotherapy?</strong></h3><p data-start=\"565\" data-end=\"788\">Hydrotherapy involves doing specific exercises in a warm-water pool under expert supervision. The water temperature is usually between <strong data-start=\"700\" data-end=\"717\">32°C and 34°C</strong>, which helps relax muscles, improve blood flow, and reduce joint pain.</p><p data-start=\"790\" data-end=\"918\">This therapy is especially useful for people who find land-based exercises difficult due to pain, weakness, or limited movement.</p><hr data-start=\"920\" data-end=\"923\"><h3 data-start=\"925\" data-end=\"958\"><strong data-start=\"929\" data-end=\"958\">How Does Water Help Heal?</strong></h3><ul data-start=\"960\" data-end=\"1351\">\r\n<li data-start=\"960\" data-end=\"1077\">\r\n<p data-start=\"962\" data-end=\"1077\"><strong data-start=\"962\" data-end=\"974\">Buoyancy</strong>: Water supports your body weight, reducing pressure on joints and muscles so you can move more freely.</p>\r\n</li>\r\n<li data-start=\"1078\" data-end=\"1173\">\r\n<p data-start=\"1080\" data-end=\"1173\"><strong data-start=\"1080\" data-end=\"1094\">Resistance</strong>: Moving in water gently strengthens muscles without the risk of heavy lifting.</p>\r\n</li>\r\n<li data-start=\"1174\" data-end=\"1258\">\r\n<p data-start=\"1176\" data-end=\"1258\"><strong data-start=\"1176\" data-end=\"1186\">Warmth</strong>: Warm water soothes aches, reduces stiffness, and promotes circulation.</p>\r\n</li>\r\n<li data-start=\"1259\" data-end=\"1351\">\r\n<p data-start=\"1261\" data-end=\"1351\"><strong data-start=\"1261\" data-end=\"1285\">Hydrostatic pressure</strong>: The pressure from water can reduce swelling and improve balance.</p>\r\n</li>\r\n</ul><hr data-start=\"1353\" data-end=\"1356\"><h3 data-start=\"1358\" data-end=\"1400\"><strong data-start=\"1362\" data-end=\"1400\">Who Can Benefit from Hydrotherapy?</strong></h3><p data-start=\"1402\" data-end=\"1457\">Hydrotherapy is helpful for many conditions, including:</p><h4 data-start=\"1459\" data-end=\"1490\"><strong data-start=\"1464\" data-end=\"1490\">Orthopedic conditions:</strong></h4><ul data-start=\"1491\" data-end=\"1624\">\r\n<li data-start=\"1491\" data-end=\"1519\">\r\n<p data-start=\"1493\" data-end=\"1519\">Arthritis and joint pain</p>\r\n</li>\r\n<li data-start=\"1520\" data-end=\"1533\">\r\n<p data-start=\"1522\" data-end=\"1533\">Back pain</p>\r\n</li>\r\n<li data-start=\"1534\" data-end=\"1590\">\r\n<p data-start=\"1536\" data-end=\"1590\">Post-surgery recovery (like hip or knee replacement)</p>\r\n</li>\r\n<li data-start=\"1591\" data-end=\"1624\">\r\n<p data-start=\"1593\" data-end=\"1624\">Sports injuries and fractures</p>\r\n</li>\r\n</ul><h4 data-start=\"1626\" data-end=\"1659\"><strong data-start=\"1631\" data-end=\"1659\">Neurological conditions:</strong></h4><ul data-start=\"1660\" data-end=\"1761\">\r\n<li data-start=\"1660\" data-end=\"1670\">\r\n<p data-start=\"1662\" data-end=\"1670\">Stroke</p>\r\n</li>\r\n<li data-start=\"1671\" data-end=\"1689\">\r\n<p data-start=\"1673\" data-end=\"1689\">Cerebral palsy</p>\r\n</li>\r\n<li data-start=\"1690\" data-end=\"1713\">\r\n<p data-start=\"1692\" data-end=\"1713\">Parkinson’s disease</p>\r\n</li>\r\n<li data-start=\"1714\" data-end=\"1736\">\r\n<p data-start=\"1716\" data-end=\"1736\">Multiple sclerosis</p>\r\n</li>\r\n<li data-start=\"1737\" data-end=\"1761\">\r\n<p data-start=\"1739\" data-end=\"1761\">Spinal cord injuries</p>\r\n</li>\r\n</ul><h4 data-start=\"1763\" data-end=\"1793\"><strong data-start=\"1768\" data-end=\"1793\">Pediatric conditions:</strong></h4><ul data-start=\"1794\" data-end=\"1881\">\r\n<li data-start=\"1794\" data-end=\"1818\">\r\n<p data-start=\"1796\" data-end=\"1818\">Developmental delays</p>\r\n</li>\r\n<li data-start=\"1819\" data-end=\"1851\">\r\n<p data-start=\"1821\" data-end=\"1851\">Muscle tightness or weakness</p>\r\n</li>\r\n<li data-start=\"1852\" data-end=\"1881\">\r\n<p data-start=\"1854\" data-end=\"1881\">Sensory processing issues</p>\r\n</li>\r\n</ul><h4 data-start=\"1883\" data-end=\"1899\"><strong data-start=\"1888\" data-end=\"1899\">Others:</strong></h4><ul data-start=\"1900\" data-end=\"2019\">\r\n<li data-start=\"1900\" data-end=\"1935\">\r\n<p data-start=\"1902\" data-end=\"1935\">Chronic fatigue or fibromyalgia</p>\r\n</li>\r\n<li data-start=\"1936\" data-end=\"1989\">\r\n<p data-start=\"1938\" data-end=\"1989\">Obesity (as a starting point for gentle exercise)</p>\r\n</li>\r\n<li data-start=\"1990\" data-end=\"2019\">\r\n<p data-start=\"1992\" data-end=\"2019\">General stress or anxiety</p>\r\n</li>\r\n</ul><hr data-start=\"2021\" data-end=\"2024\"><h3 data-start=\"2026\" data-end=\"2077\"><strong data-start=\"2030\" data-end=\"2077\">What Happens During a Hydrotherapy Session?</strong></h3><ol data-start=\"2079\" data-end=\"2521\">\r\n<li data-start=\"2079\" data-end=\"2174\">\r\n<p data-start=\"2082\" data-end=\"2174\"><strong data-start=\"2082\" data-end=\"2097\">Assessment:</strong> We evaluate your condition, medical history, and goals to plan your therapy.</p>\r\n</li>\r\n<li data-start=\"2175\" data-end=\"2239\">\r\n<p data-start=\"2178\" data-end=\"2239\"><strong data-start=\"2178\" data-end=\"2190\">Warm-up:</strong> Gentle stretching or floating to relax the body.</p>\r\n</li>\r\n<li data-start=\"2240\" data-end=\"2448\">\r\n<p data-start=\"2243\" data-end=\"2288\"><strong data-start=\"2243\" data-end=\"2269\">Therapeutic Exercises:</strong> These may include:</p>\r\n<ul data-start=\"2292\" data-end=\"2448\">\r\n<li data-start=\"2292\" data-end=\"2324\">\r\n<p data-start=\"2294\" data-end=\"2324\">Walking or marching in water</p>\r\n</li>\r\n<li data-start=\"2328\" data-end=\"2366\">\r\n<p data-start=\"2330\" data-end=\"2366\">Arm and leg movements for strength</p>\r\n</li>\r\n<li data-start=\"2370\" data-end=\"2405\">\r\n<p data-start=\"2372\" data-end=\"2405\">Balance and coordination drills</p>\r\n</li>\r\n<li data-start=\"2409\" data-end=\"2448\">\r\n<p data-start=\"2411\" data-end=\"2448\">Breathing and relaxation techniques</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"2449\" data-end=\"2521\">\r\n<p data-start=\"2452\" data-end=\"2521\"><strong data-start=\"2452\" data-end=\"2466\">Cool-down:</strong> Light movements or floating to calm the body and mind.</p>\r\n</li>\r\n</ol><p data-start=\"2523\" data-end=\"2707\">Sessions are supervised by trained physiotherapists to ensure safety and effectiveness. Non-swimmers are also welcome—most pools are shallow and support tools like floats are provided.</p><hr data-start=\"2709\" data-end=\"2712\"><h3 data-start=\"2714\" data-end=\"2746\"><strong data-start=\"2718\" data-end=\"2746\">Benefits of Hydrotherapy</strong></h3><ul data-start=\"2748\" data-end=\"3035\">\r\n<li data-start=\"2748\" data-end=\"2778\">\r\n<p data-start=\"2750\" data-end=\"2778\">Reduces pain and stiffness</p>\r\n</li>\r\n<li data-start=\"2779\" data-end=\"2829\">\r\n<p data-start=\"2781\" data-end=\"2829\">Improves muscle strength and joint flexibility</p>\r\n</li>\r\n<li data-start=\"2830\" data-end=\"2867\">\r\n<p data-start=\"2832\" data-end=\"2867\">Enhances balance and coordination</p>\r\n</li>\r\n<li data-start=\"2868\" data-end=\"2914\">\r\n<p data-start=\"2870\" data-end=\"2914\">Speeds up recovery after surgery or injury</p>\r\n</li>\r\n<li data-start=\"2915\" data-end=\"2952\">\r\n<p data-start=\"2917\" data-end=\"2952\">Reduces swelling and inflammation</p>\r\n</li>\r\n<li data-start=\"2953\" data-end=\"2986\">\r\n<p data-start=\"2955\" data-end=\"2986\">Boosts confidence in movement</p>\r\n</li>\r\n<li data-start=\"2987\" data-end=\"3035\">\r\n<p data-start=\"2989\" data-end=\"3035\">Relieves stress and promotes mental relaxation</p>\r\n</li>\r\n</ul><hr data-start=\"3037\" data-end=\"3040\"><h3 data-start=\"3042\" data-end=\"3064\"><strong data-start=\"3046\" data-end=\"3064\">Why Choose Us?</strong></h3><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><ul data-start=\"3066\" data-end=\"3326\">\r\n<li data-start=\"3066\" data-end=\"3113\">\r\n<p data-start=\"3068\" data-end=\"3113\"><strong data-start=\"3068\" data-end=\"3111\">Qualified hydrotherapy physiotherapists</strong></p>\r\n</li>\r\n<li data-start=\"3114\" data-end=\"3157\">\r\n<p data-start=\"3116\" data-end=\"3157\"><strong data-start=\"3116\" data-end=\"3155\">Clean, temperature-controlled pools</strong></p>\r\n</li>\r\n<li data-start=\"3158\" data-end=\"3213\">\r\n<p data-start=\"3160\" data-end=\"3213\">Individual or group sessions based on comfort level</p>\r\n</li>\r\n<li data-start=\"3214\" data-end=\"3274\">\r\n<p data-start=\"3216\" data-end=\"3274\"><strong data-start=\"3216\" data-end=\"3245\">Customized exercise plans</strong> for all ages and abilities</p>\r\n</li>\r\n<li data-start=\"3275\" data-end=\"3326\">\r\n<p data-start=\"3277\" data-end=\"3326\">Safe environment with friendly, professional care</p></li></ul>', 1, '2025-06-24 00:53:29', '2025-06-24 00:53:29'),
(23, 'Customised Treatment Plan', '1750748339.jpg', 'service', '<p data-start=\"98\" data-end=\"461\">A <strong data-start=\"100\" data-end=\"118\">treatment plan</strong> is a personalized roadmap created by your healthcare team to guide your recovery, healing, or therapy journey. It outlines what you need, why you need it, and how we’ll work together to reach your goals. This plan is based on the findings from your <strong data-start=\"368\" data-end=\"390\">initial evaluation</strong> and is tailored to your specific condition, age, needs, and lifestyle.</p><p data-start=\"463\" data-end=\"548\">At our center, we believe every person is unique—so your treatment plan will be, too.</p><hr data-start=\"550\" data-end=\"553\"><h3 data-start=\"555\" data-end=\"588\"><strong data-start=\"559\" data-end=\"588\">What Is a Treatment Plan?</strong></h3><p data-start=\"590\" data-end=\"753\">A treatment plan is a step-by-step guide designed by professionals such as physiotherapists, occupational therapists, speech therapists, or doctors. It focuses on:</p><ul data-start=\"754\" data-end=\"1087\">\r\n<li data-start=\"754\" data-end=\"830\">\r\n<p data-start=\"756\" data-end=\"830\"><strong data-start=\"756\" data-end=\"784\">What you need to work on</strong> (like walking, speaking, or using your hands)</p>\r\n</li>\r\n<li data-start=\"831\" data-end=\"914\">\r\n<p data-start=\"833\" data-end=\"914\"><strong data-start=\"833\" data-end=\"857\">How we will treat it</strong> (like exercises, therapy sessions, or assistive devices)</p>\r\n</li>\r\n<li data-start=\"915\" data-end=\"997\">\r\n<p data-start=\"917\" data-end=\"997\"><strong data-start=\"917\" data-end=\"948\">What goals we want to reach</strong> (like walking independently or improving speech)</p>\r\n</li>\r\n<li data-start=\"998\" data-end=\"1087\">\r\n<p data-start=\"1000\" data-end=\"1087\"><strong data-start=\"1000\" data-end=\"1044\">How often and how long therapy is needed</strong> (example: 3 sessions per week for 4 weeks)</p>\r\n</li>\r\n</ul><p data-start=\"1089\" data-end=\"1159\">This plan keeps you, your family, and your therapist on the same page.</p><hr data-start=\"1161\" data-end=\"1164\"><h3 data-start=\"1166\" data-end=\"1203\"><strong data-start=\"1170\" data-end=\"1203\">Key Parts of a Treatment Plan</strong></h3><h4 data-start=\"1205\" data-end=\"1239\">1. <strong data-start=\"1213\" data-end=\"1239\">Diagnosis or Condition</strong></h4><p data-start=\"1240\" data-end=\"1361\">We clearly note your health condition—whether it’s a stroke, arthritis, autism, injury, cerebral palsy, or anything else.</p><h4 data-start=\"1363\" data-end=\"1391\">2. <strong data-start=\"1371\" data-end=\"1391\">Short-Term Goals</strong></h4><p data-start=\"1392\" data-end=\"1468\">These are smaller goals you can achieve in the first few weeks. For example:</p><ul data-start=\"1469\" data-end=\"1589\">\r\n<li data-start=\"1469\" data-end=\"1499\">\r\n<p data-start=\"1471\" data-end=\"1499\">Walk 10 steps with support</p>\r\n</li>\r\n<li data-start=\"1500\" data-end=\"1530\">\r\n<p data-start=\"1502\" data-end=\"1530\">Improve hand grip strength</p>\r\n</li>\r\n<li data-start=\"1531\" data-end=\"1555\">\r\n<p data-start=\"1533\" data-end=\"1555\">Say 3-word sentences</p>\r\n</li>\r\n<li data-start=\"1556\" data-end=\"1589\">\r\n<p data-start=\"1558\" data-end=\"1589\">Reduce pain from 8/10 to 4/10</p>\r\n</li>\r\n</ul><h4 data-start=\"1591\" data-end=\"1618\">3. <strong data-start=\"1599\" data-end=\"1618\">Long-Term Goals</strong></h4><p data-start=\"1619\" data-end=\"1654\">These are your final targets, like:</p><ul data-start=\"1655\" data-end=\"1788\">\r\n<li data-start=\"1655\" data-end=\"1680\">\r\n<p data-start=\"1657\" data-end=\"1680\">Walk without a walker</p>\r\n</li>\r\n<li data-start=\"1681\" data-end=\"1709\">\r\n<p data-start=\"1683\" data-end=\"1709\">Return to work or school</p>\r\n</li>\r\n<li data-start=\"1710\" data-end=\"1752\">\r\n<p data-start=\"1712\" data-end=\"1752\">Perform daily activities independently</p>\r\n</li>\r\n<li data-start=\"1753\" data-end=\"1788\">\r\n<p data-start=\"1755\" data-end=\"1788\">Speak clearly in full sentences</p>\r\n</li>\r\n</ul><h4 data-start=\"1790\" data-end=\"1819\">4. <strong data-start=\"1798\" data-end=\"1819\">Treatment Methods</strong></h4><p data-start=\"1820\" data-end=\"1871\">Depending on your condition, your plan may include:</p><ul data-start=\"1872\" data-end=\"2210\">\r\n<li data-start=\"1872\" data-end=\"1928\">\r\n<p data-start=\"1874\" data-end=\"1928\">Physiotherapy: exercises, stretching, manual therapy</p>\r\n</li>\r\n<li data-start=\"1929\" data-end=\"1994\">\r\n<p data-start=\"1931\" data-end=\"1994\">Occupational therapy: hand function training, self-care tasks</p>\r\n</li>\r\n<li data-start=\"1995\" data-end=\"2064\">\r\n<p data-start=\"1997\" data-end=\"2064\">Speech therapy: communication, language, and swallowing exercises</p>\r\n</li>\r\n<li data-start=\"2065\" data-end=\"2114\">\r\n<p data-start=\"2067\" data-end=\"2114\">Strengthening, balance, or endurance training</p>\r\n</li>\r\n<li data-start=\"2115\" data-end=\"2148\">\r\n<p data-start=\"2117\" data-end=\"2148\">Hydrotherapy or gait training</p>\r\n</li>\r\n<li data-start=\"2149\" data-end=\"2210\">\r\n<p data-start=\"2151\" data-end=\"2210\">Use of assistive devices like walkers, braces, or splints</p>\r\n</li>\r\n</ul><h4 data-start=\"2212\" data-end=\"2245\">5. <strong data-start=\"2220\" data-end=\"2245\">Schedule and Duration</strong></h4><p data-start=\"2246\" data-end=\"2405\">We decide how many sessions you’ll need per week, and how long each session will be (30–60 minutes). The overall plan might last a few weeks to several months.</p><h4 data-start=\"2407\" data-end=\"2436\">6. <strong data-start=\"2415\" data-end=\"2436\">Progress Tracking</strong></h4><p data-start=\"2437\" data-end=\"2506\">We regularly measure your improvement and update your plan as needed.</p><hr data-start=\"2508\" data-end=\"2511\"><h3 data-start=\"2513\" data-end=\"2555\"><strong data-start=\"2517\" data-end=\"2555\">Why Is a Treatment Plan Important?</strong></h3><ul data-start=\"2557\" data-end=\"2800\">\r\n<li data-start=\"2557\" data-end=\"2602\">\r\n<p data-start=\"2559\" data-end=\"2602\">Gives you <strong data-start=\"2569\" data-end=\"2600\">clear direction and purpose</strong></p>\r\n</li>\r\n<li data-start=\"2603\" data-end=\"2651\">\r\n<p data-start=\"2605\" data-end=\"2651\">Helps you and your family <strong data-start=\"2631\" data-end=\"2649\">stay motivated</strong></p>\r\n</li>\r\n<li data-start=\"2652\" data-end=\"2686\">\r\n<p data-start=\"2654\" data-end=\"2686\">Tracks your progress over time</p>\r\n</li>\r\n<li data-start=\"2687\" data-end=\"2738\">\r\n<p data-start=\"2689\" data-end=\"2738\">Ensures the care is <strong data-start=\"2709\" data-end=\"2736\">organized and effective</strong></p>\r\n</li>\r\n<li data-start=\"2739\" data-end=\"2800\">\r\n<p data-start=\"2741\" data-end=\"2800\">Allows the therapy team to <strong data-start=\"2768\" data-end=\"2800\">adjust things as you improve</strong></p>\r\n</li>\r\n</ul><hr data-start=\"2802\" data-end=\"2805\"><h3 data-start=\"2807\" data-end=\"2845\"><strong data-start=\"2811\" data-end=\"2845\">What Is Your Role in the Plan?</strong></h3><p data-start=\"2847\" data-end=\"2907\">You are the most important part of your treatment. You will:</p><p data-start=\"92\" data-end=\"401\">\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><ul data-start=\"2908\" data-end=\"3075\">\r\n<li data-start=\"2908\" data-end=\"2945\">\r\n<p data-start=\"2910\" data-end=\"2945\">Attend therapy sessions regularly</p>\r\n</li>\r\n<li data-start=\"2946\" data-end=\"2982\">\r\n<p data-start=\"2948\" data-end=\"2982\">Follow home exercises and advice</p>\r\n</li>\r\n<li data-start=\"2983\" data-end=\"3026\">\r\n<p data-start=\"2985\" data-end=\"3026\">Share feedback about pain or difficulty</p>\r\n</li>\r\n<li data-start=\"3027\" data-end=\"3075\">\r\n<p data-start=\"3029\" data-end=\"3075\">Stay positive and patient—recovery takes time!</p>\r\n</li>\r\n</ul>', 1, '2025-06-24 01:28:59', '2025-10-07 07:36:49'),
(25, 'Spinal Cord Injury', '1751612602.jpg', 'specialist', '<p data-start=\"146\" data-end=\"502\">A <strong data-start=\"148\" data-end=\"176\">spinal cord injury (SCI)</strong> is damage to the spinal cord, the bundle of nerves that runs down your back and carries messages between your brain and body. Think of it like the body’s information highway. If this highway gets damaged, the messages can’t travel properly. This can affect movement, sensation (like touch and pain), and even how organs work.</p><h4 data-start=\"504\" data-end=\"523\">How It Happens</h4><p data-start=\"525\" data-end=\"780\">Spinal cord injuries usually happen because of accidents, like car crashes, falls, sports injuries, or violence (such as gunshot wounds). Some people also get spinal cord damage from diseases like cancer, infections, or conditions like multiple sclerosis.</p><p data-start=\"782\" data-end=\"814\">There are two main types of SCI:</p><ul data-start=\"815\" data-end=\"923\">\r\n<li data-start=\"815\" data-end=\"871\">\r\n<p data-start=\"817\" data-end=\"871\"><strong data-start=\"817\" data-end=\"829\">Complete</strong>: No feeling or movement below the injury.</p>\r\n</li>\r\n<li data-start=\"872\" data-end=\"923\">\r\n<p data-start=\"874\" data-end=\"923\"><strong data-start=\"874\" data-end=\"888\">Incomplete</strong>: Some movement or feeling remains.</p>\r\n</li>\r\n</ul><p data-start=\"925\" data-end=\"1219\">The higher up the injury is on the spine, the more of the body it can affect. For example, an injury to the neck (called a <strong data-start=\"1048\" data-end=\"1067\">cervical injury</strong>) can cause paralysis in both the arms and legs (called <strong data-start=\"1123\" data-end=\"1139\">quadriplegia</strong>), while a lower back injury might only affect the legs (called <strong data-start=\"1203\" data-end=\"1217\">paraplegia</strong>).</p><h4 data-start=\"1221\" data-end=\"1244\">What It Feels Like</h4><p data-start=\"1246\" data-end=\"1357\">Right after the injury, a person might be in shock and unable to feel much. Later, they may have symptoms like:</p><ul data-start=\"1358\" data-end=\"1550\">\r\n<li data-start=\"1358\" data-end=\"1389\">\r\n<p data-start=\"1360\" data-end=\"1389\">Loss of movement or sensation</p>\r\n</li>\r\n<li data-start=\"1390\" data-end=\"1417\">\r\n<p data-start=\"1392\" data-end=\"1417\">Muscle weakness or spasms</p>\r\n</li>\r\n<li data-start=\"1418\" data-end=\"1458\">\r\n<p data-start=\"1420\" data-end=\"1458\">Problems with bladder or bowel control</p>\r\n</li>\r\n<li data-start=\"1459\" data-end=\"1515\">\r\n<p data-start=\"1461\" data-end=\"1515\">Breathing difficulties (especially with high injuries)</p>\r\n</li>\r\n<li data-start=\"1516\" data-end=\"1550\">\r\n<p data-start=\"1518\" data-end=\"1550\">Pain or strange nerve sensations</p>\r\n</li>\r\n</ul><p data-start=\"1552\" data-end=\"1655\">Every case is different. Some people recover some function, while others may face permanent disability.</p><h4 data-start=\"1657\" data-end=\"1682\">Life After an Injury</h4><p data-start=\"1684\" data-end=\"1927\">A spinal cord injury can change a person’s life in major ways. It often requires physical therapy, assistive devices (like wheelchairs), and long-term medical care. But with support and the right tools, many people live full, meaningful lives.</p><p data-start=\"1929\" data-end=\"2156\">Medical advances are improving. Treatments like steroids (to reduce swelling), surgery, and rehabilitation help recovery. Research is also looking into nerve regeneration, stem cells, and robotic technology to improve outcomes.</p><h4 data-start=\"2158\" data-end=\"2179\">Support and Hope</h4><p data-start=\"2181\" data-end=\"2495\">Adjusting to a spinal cord injury is tough—physically, emotionally, and socially. It’s normal to feel grief, anger, or fear. That’s why support from family, friends, therapists, and counselors is so important. Many people with SCIs go back to work, school, or sports, and become powerful advocates and role models.</p><h4 data-start=\"2497\" data-end=\"2512\">Prevention</h4><p data-start=\"2514\" data-end=\"2583\">Not all spinal cord injuries can be prevented, but safety steps help:</p><ul data-start=\"2584\" data-end=\"2713\">\r\n<li data-start=\"2584\" data-end=\"2610\">\r\n<p data-start=\"2586\" data-end=\"2610\">Wear seat belts in cars.</p>\r\n</li>\r\n<li data-start=\"2611\" data-end=\"2643\">\r\n<p data-start=\"2613\" data-end=\"2643\">Use proper gear during sports.</p>\r\n</li>\r\n<li data-start=\"2644\" data-end=\"2667\">\r\n<p data-start=\"2646\" data-end=\"2667\">Avoid risky behavior.</p>\r\n</li>\r\n<li data-start=\"2668\" data-end=\"2713\">\r\n<p data-start=\"2670\" data-end=\"2713\">Prevent falls, especially for older adults.</p>\r\n</li>\r\n</ul><hr data-start=\"2715\" data-end=\"2718\"><h3 data-start=\"2720\" data-end=\"2734\">In Summary</h3><p>\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n</p><p data-start=\"2736\" data-end=\"3066\">A spinal cord injury is a serious, life-changing event. It can affect movement, feeling, and many body functions, depending on where and how badly the spine is hurt. But with today’s treatments and support systems, people with SCIs can still live rich, fulfilling lives. Knowledge, awareness, and compassion make a big difference.</p>', 1, '2025-07-04 07:03:22', '2025-10-07 07:32:51'),
(26, 'Parkinson Disease', '1759822413.jpg', 'specialist', '<p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Parkinson\'s disease</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> is a neurological condition that worsens over time and impairs coordination and mobility. It occurs when nerve cells in the brain that produce </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">dopamine </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">— a chemical responsible for smooth, controlled muscle movement — begin to degenerate. Patients suffer from symptoms like </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">tremors</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">, </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">stiffness</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">, </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">delayed movement (bradykinesia),</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> and </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">balance </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">issues when dopamine levels drop. </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Parkinson’s disease</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> usually develops gradually and may start with a slight tremor in one hand or mild difficulty in coordination.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><br></span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">At our clinic, we specialize in the </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">diagnosis</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">, </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">treatment</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">, and </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">management </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">of </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Parkinson’s disease</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">. Our team of experienced neurologists and movement disorder specialists uses </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">advanced diagnostic techniques</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">, </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">including neurological examinations</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">, </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">brain imaging</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">, and </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">medical history evaluations</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">, to identify the condition accurately. While </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Parkinson’s disease</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> has no </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">complete cure</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">, </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">early diagnosis</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> and </span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">personalized treatment</span><span style=\"font-size:11pt;font-family:Arial,sans-serif;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> can significantly improve quality of life.</span></p>', 1, '2025-10-07 07:33:33', '2025-11-05 07:00:04'),
(27, 'Electrotherapy', '1759822501.jpg', 'service', '<p data-start=\"177\" data-end=\"688\"><strong data-start=\"177\" data-end=\"195\">Electrotherapy</strong> is an advanced physiotherapy treatment that uses controlled electrical energy to reduce pain, improve muscle strength, and promote healing. It is widely used by <strong data-start=\"357\" data-end=\"408\">physiotherapists and rehabilitation specialists</strong> to treat both <strong data-start=\"423\" data-end=\"460\">acute and chronic pain conditions</strong>. By applying mild electrical impulses to targeted areas of the body, electrotherapy helps <strong data-start=\"551\" data-end=\"618\">stimulate nerves, increase blood circulation, and relax muscles</strong>, offering a non-invasive and drug-free approach to pain management.</p><p data-start=\"690\" data-end=\"1265\">At our clinic, we provide <strong data-start=\"716\" data-end=\"751\">modern electrotherapy treatment</strong> using the latest equipment and safe, clinically proven techniques. Our experienced <strong data-start=\"835\" data-end=\"855\">physiotherapists</strong> carefully assess each patient’s condition before customizing the intensity and duration of therapy. Electrotherapy is beneficial for a variety of conditions including <strong data-start=\"1023\" data-end=\"1145\">back pain, neck pain, arthritis, joint stiffness, sciatica, muscle spasms, sports injuries, and post-surgical recovery</strong>. It is also effective in <strong data-start=\"1171\" data-end=\"1209\">reducing inflammation and swelling</strong>, which helps restore normal movement and flexibility.</p><p>\r\n\r\n</p><p data-start=\"1267\" data-end=\"1705\">We offer several types of electrotherapy, such as <strong data-start=\"1317\" data-end=\"1371\">TENS (Transcutaneous Electrical Nerve Stimulation)</strong> for pain relief, <strong data-start=\"1389\" data-end=\"1411\">Ultrasound Therapy</strong> for deep tissue healing, <strong data-start=\"1437\" data-end=\"1469\">Interferential Therapy (IFT)</strong> for muscle stimulation, and <strong data-start=\"1498\" data-end=\"1537\">Electrical Muscle Stimulation (EMS)</strong> to improve strength in weak muscles. Each session is designed to be <strong data-start=\"1606\" data-end=\"1649\">comfortable, safe, and highly effective</strong>, ensuring visible improvement with regular treatment.</p>', 1, '2025-10-07 07:35:01', '2025-10-07 07:35:01');

